@patch
def pageranks(self:CodeGraph, nodes) -> dict:
    'Bulk {node: pagerank} lookup for a list of node names (used by context rerank).'
    ns = list({n for n in listify(nodes) if n})
    if not ns: return {}
    pl = ','.join('?'*len(ns))
    o = self.gn(select='node,pagerank', where=f'node IN ({pl})', where_args=ns)
    return {r['node']: r['pagerank'] or 0.0 for r in o}

