@patch
def _chunk_at(self:Kosha, path:str, line:int=None):
	'Find the indexed chunk covering path:line (narrowest span wins). Falls back to suffix path match.'
	p = Path(path)
	ap = str((self.root/p).resolve()) if not p.is_absolute() else str(p)
	sel = 'id,content,embedding,metadata'
	cand = self.code_st(where='path = ?', where_args=[ap], select=sel)
	if not cand: cand = self.code_st(where='path LIKE ?', where_args=[f'%{path}'], select=sel)
	rows = [r | dict(metadata=jl(r['metadata']) if isinstance(r['metadata'], str) else r['metadata']) for r in cand]
	if not rows: return None
	_ln = lambda r, k: r['metadata'].get(k) or 0
	if line:
		cov = [r for r in rows if _ln(r,'lineno') <= line <= (_ln(r,'end_lineno') or _ln(r,'lineno'))]
		if cov: return min(cov, key=lambda r: (_ln(r,'end_lineno') or _ln(r,'lineno')) - _ln(r,'lineno'))
		return min(rows, key=lambda r: abs(_ln(r,'lineno') - line))
	return min(rows, key=lambda r: _ln(r,'lineno'))

@patch
def find_related(self:Kosha,
	path: str,          # file path (absolute, or relative to repo root)
	line: int = None,   # line number the chunk should cover; None = first chunk in file
	limit: int = 10,    # max related chunks
	env: bool = True,   # also search installed-package chunks
	graph: bool = True  # include call-graph neighborhood of the source chunk
) -> dict:
	'Chunks semantically similar to the code at path:line, plus its call-graph neighborhood.'
	src = self._chunk_at(path, line)
	if not src: return dict(source=None, related=L(), error=f'no indexed chunk found for {path}:{line}')
	m, emb = src['metadata'], src['embedding']
	fn = lambda r, s: (r | dict(metadata=jl(r['metadata']) if isinstance(r.get('metadata'), str) else r.get('metadata'),
	                            _store=s))
	if emb is not None:
		rc = self.code_st.vec_search(emb, columns=['rowid','id','content','path','metadata'],
		                             where='id != :sid', where_args=dict(sid=src['id']), limit=limit)
		re_ = self.env_st.vec_search(emb, columns=['rowid','id','content','package','metadata'],
		                             limit=limit) if env else []
		rel = L(sorted([fn(r,'repo') for r in rc] + [fn(r,'env') for r in re_],
		               key=lambda r: r.get('_dist', 1)))[:limit]
	else:
		q = ' '.join(split_ident(m.get('name') or Path(path).stem))
		rel = self.repo_context(q, limit=limit, log=False)[:limit]
	out = dict(source=filter_keys(m, in_(['mod_name','path','name','lineno','end_lineno'])), related=rel)
	if graph and m.get('mod_name'): out |= self.ni(m['mod_name'])
	self._log_savings('find_related', rel)
	return out
